import * as React from 'react';

import { Slot } from '@/components/ui/_lib/slot-polyfill';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '@/lib/utils';

const badgeVariants = cva(
  'inline-flex items-center justify-center rounded-md border px-1.5 py-0.3 text-xs font-medium w-fit whitespace-nowrap shrink-0 [&>svg]:size-3 gap-1 [&>svg]:pointer-events-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive transition-[color,box-shadow] overflow-hidden',
  {
    variants: {
      variant: {
        default:
          'border-transparent bg-primary text-primary-foreground [a&]:hover:bg-primary/90',
        secondary:
          'border-transparent bg-secondary text-secondary-foreground [a&]:hover:bg-secondary/90',
        destructive:
          'border-transparent bg-destructive text-white [a&]:hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60',
        outline:
          'text-foreground [a&]:hover:bg-accent [a&]:hover:text-accent-foreground'
      }
    },
    defaultVariants: {
      variant: 'default'
    }
  }
);

function Badge({
  className,
  variant,
  asChild = false,
  ...props
}: React.ComponentProps<'span'> &
  VariantProps<typeof badgeVariants> & { asChild?: boolean }) {
  const Comp = asChild ? Slot : 'span';

  return (
    <Comp
      data-slot="badge"
      className={cn(badgeVariants({ variant }), className)}
      {...props}
    />
  );
}

export { Badge, badgeVariants };

import * as React from 'react';

import { cn } from '@/lib/utils';

function mergeProps(
  slotProps: Record<string, unknown>,
  childProps: Record<string, unknown>
) {
  const merged: Record<string, unknown> = { ...slotProps };

  for (const propName of Object.keys(childProps)) {
    const slotPropValue = slotProps[propName];
    const childPropValue = childProps[propName];

    if (propName === 'className') {
      merged[propName] = cn(
        slotPropValue as string | undefined,
        childPropValue as string | undefined
      );
    } else if (
      typeof slotPropValue === 'function' &&
      typeof childPropValue === 'function'
    ) {
      merged[propName] = (...args: unknown[]) => {
        (slotPropValue as (...args: unknown[]) => void)(...args);
        (childPropValue as (...args: unknown[]) => void)(...args);
      };
    } else {
      merged[propName] = childPropValue;
    }
  }

  return merged;
}

function SlotClone({
  children,
  ...props
}: React.PropsWithChildren<Record<string, unknown>>) {
  if (React.Children.count(children) === 1 && React.isValidElement(children)) {
    return React.cloneElement(
      children,
      mergeProps(props, children.props as Record<string, unknown>)
    );
  }

  return <>{children}</>;
}

const Slot = React.forwardRef<
  HTMLElement,
  React.HTMLAttributes<HTMLElement> & { children?: React.ReactNode }
>(({ children, ...props }, ref) => {
  return (
    <SlotClone {...props} ref={ref}>
      {children}
    </SlotClone>
  );
});
Slot.displayName = 'Slot';

export { Slot };
